beforeSaveCustomScript:
dateEnd=null;

$prospectId = record\findOne('Prospect', null, null, 'name=', parentName);

if ($prospectId) {
    prospectId = $prospectId;
}

if ((telefono == null || telefono == '') && prospectId != null) {
    telefono = prospect.phoneNumber;
}

if (telefono != null && telefono != '') {
    whatsAppNumero = string\concatenate('https://wa.me/', '+39', telefono);
}

$skipAutoName = nota != null && (string\contains(nota, 'Auto-Pending-Appuntamento:') || string\contains(nota, 'Auto-Richiamo-Appuntamento:') || string\contains(nota, 'Auto-Rinvio-Call:') || string\contains(nota, 'Auto-Richiamo-Call:'));

if (!$skipAutoName && dateStart != null && parentName != null && tipologia != null) {
    name = string\upperCase(string\concatenate(datetime\format(dateStart, 'Europe/Rome', 'DD/MM/YYYY HH:mm'), ' - ', tipologia, ' - ', parentName, ' - ', telefono));
}
